            if (this.isSingleFrame) {
                return;
            }
            if (this.totalFrames == 1) {
                this.isSingleFrame = true;
            }
            var currentPath = exportRoot.farm;
            var fpsTick = 60; // fluiditate joc
            var mapSensivity = 1; // cu cat e mai mic cu atat se trage harta mai greu
