            this.showInPlace = function(movieclip, position, timeouttimer) {
                if (position == "bottom-top") {
                    var currentYPosition = movieclip.y;

                    movieclip.y = currentYPosition + 150;
                    movieclip.visible = true;

                    setTimeout(function() {
                        createjs.Tween.get(movieclip, {
                                loop: false
                            })
                            .to({
                                y: currentYPosition - 30
                            }, 500, createjs.Ease.getPowOut(2.2))
                            .to({
                                y: currentYPosition
                            }, 300, createjs.Ease.getPowOut(2.2));
                    }, timeouttimer);

                }

                if (position == "top-bottom") {
                    var currentYPosition = movieclip.y;

                    movieclip.y = currentYPosition - 150;
                    movieclip.visible = true;

                    setTimeout(function() {
                        createjs.Tween.get(movieclip, {
                                loop: false
                            })
                            .to({
                                y: currentYPosition + 30
                            }, 500, createjs.Ease.getPowOut(2.2))
                            .to({
                                y: currentYPosition
                            }, 300, createjs.Ease.getPowOut(2.2));
                    }, timeouttimer);

                }

            }


