            function detect_parent() {
                var iframe = (parent !== window);
                var url = null;
                if (iframe) {
                    url = document.referrer;
                    ref = url.match(/:\/\/(.[^/]+)/)[1];
                    return ref;
                }
                return "gamedistribution";
            }
